mapper.select:
SELECT * FROM hot_stamping_type_compatibility
WHERE hot_stamping_type_id = #{hotStampingTypeId}
ORDER BY product_name

SELECT COUNT(*) 
FROM hot_stamping_type_compatibility
WHERE product_name = #{productName} 
AND hot_stamping_type_id = #{hotStampingTypeId}

SELECT COUNT(*)
FROM hot_stamping_type_compatibility
WHERE hot_stamping_type_id = #{hotStampingTypeId}

SELECT id, product_name as productName, hot_stamping_type_id as hotStampingTypeId,
       compatibility_status as compatibilityStatus, paper_type as paperType,
       created_at as createdAt, updated_at as updatedAt
FROM hot_stamping_type_compatibility
WHERE product_name = #{productName}
  AND paper_type = #{paperType}
  AND hot_stamping_type_id = #{hotStampingTypeId}
LIMIT 1
